import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { Observable, map } from 'rxjs';
import { environment } from '../../../environments/environment';
import { Role, User } from '../models';

const TOKEN_KEY = 'auth_token';
const ACCESS_KEY = 'access_token';
const USER_KEY = 'user';
const ROLE_KEY = 'role';
const AUTH_FLAG = 'isAuthenticated';

// Backend auth response: { access_token, user: { id, email, role, name } }
interface AuthResponse {
  access_token?: string;
  token?: string;
  user: User;
}

// Live auth service. Talks to the NestJS backend at /api/auth/login and stores the
// real JWT so the interceptor can attach it to every subsequent request.
// BeehiveWatch has a single privileged `editor` role; browse/detail views are public.
@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;

  private _user = signal<User | null>(this.readUser());

  readonly user = this._user.asReadonly();
  readonly isLoggedIn = computed(() => !!this._user());
  readonly role = computed<Role | null>(() => this._user()?.role ?? null);
  /** Editor is the only privileged actor; gates every write control in the UI. */
  readonly isEditor = computed(() => this._user()?.role === 'editor');

  constructor(
    private http: HttpClient,
    private router: Router,
  ) {}

  /** Verify editor credentials against the backend and persist the returned JWT + user. */
  login(email: string, password: string): Observable<{ user: User; token: string }> {
    return this.http
      .post<AuthResponse>(`${this.apiUrl}/auth/login`, { email, password })
      .pipe(map((res) => this.handleAuth(res)));
  }

  /**
   * Demo Mode — bypasses the live backend so reviewers can inspect the full
   * editor UI (and the screenshot pipeline can capture write controls).
   * Logs in as the seeded editor and lands on the bills list.
   */
  demoLogin(): void {
    const demoUser: User = {
      id: 'demo-editor',
      email: 'editor@beehivewatch.dev',
      role: 'editor',
      name: 'Demo Editor',
    };
    this.persist(demoUser, 'demo-token');
    this.router.navigate(['/bills']);
  }

  logout(): void {
    [TOKEN_KEY, ACCESS_KEY, USER_KEY, ROLE_KEY, AUTH_FLAG, 'token'].forEach((k) =>
      localStorage.removeItem(k),
    );
    this._user.set(null);
    this.router.navigate(['/bills']);
  }

  hasRole(...roles: Role[]): boolean {
    const r = this.role();
    return !!r && roles.includes(r);
  }

  private handleAuth(res: AuthResponse): { user: User; token: string } {
    const token = res.access_token ?? res.token ?? '';
    this.persist(res.user, token);
    return { user: res.user, token };
  }

  private persist(user: User, token: string): void {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(ACCESS_KEY, token);
    localStorage.setItem('token', token);
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    localStorage.setItem(ROLE_KEY, user.role);
    localStorage.setItem(AUTH_FLAG, 'true');
    this._user.set(user);
  }

  private readUser(): User | null {
    try {
      const raw = localStorage.getItem(USER_KEY);
      return raw ? (JSON.parse(raw) as User) : null;
    } catch {
      return null;
    }
  }
}
